-- Create DQE Lab Management Database\nCREATE DATABASE DQELabDB;\nGO\n\nUSE DQELabDB;\nGO\n\n-- Users Table\nCREATE TABLE Users (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    Name NVARCHAR(255) NOT NULL,\n    Email NVARCHAR(255) NOT NULL UNIQUE,\n    Department NVARCHAR(255),\n    Role NVARCHAR(50) DEFAULT 'user', -- admin, manager, user\n    AzureId NVARCHAR(255),\n    IsActive BIT DEFAULT 1,\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    UpdatedAt DATETIME DEFAULT GETDATE()\n);\nGO\n\n-- Equipment Table\nCREATE TABLE Equipment (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    Name NVARCHAR(255) NOT NULL,\n    Model NVARCHAR(255) NOT NULL,\n    Location NVARCHAR(255),\n    Status NVARCHAR(50) DEFAULT 'available', -- available, in-use, maintenance, reserved\n    Description NVARCHAR(MAX),\n    Icon NVARCHAR(255),\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    UpdatedAt DATETIME DEFAULT GETDATE()\n);\nGO\n\n-- Test Request Table\nCREATE TABLE TestRequests (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    RequestNumber NVARCHAR(100) NOT NULL UNIQUE,\n    EquipmentId INT NOT NULL,\n    CustomerId INT,\n    Customer NVARCHAR(255) NOT NULL,\n    TestPhase NVARCHAR(50) NOT NULL, -- EVT, PTT, MP, ORT\n    EstimatedStartDate DATETIME NOT NULL,\n    EstimatedEndDate DATETIME NOT NULL,\n    RequesterId INT NOT NULL,\n    Requester NVARCHAR(255),\n    SampleCount INT DEFAULT 0,\n    Status NVARCHAR(50) DEFAULT 'open', -- open, in-progress, completed, cancelled\n    Description NVARCHAR(MAX),\n    RequestDate DATETIME DEFAULT GETDATE(),\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    UpdatedAt DATETIME DEFAULT GETDATE(),\n    FOREIGN KEY (EquipmentId) REFERENCES Equipment(Id),\n    FOREIGN KEY (RequesterId) REFERENCES Users(Id)\n);\nGO\n\n-- Equipment Booking Table\nCREATE TABLE Bookings (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    RequestId INT NOT NULL,\n    EquipmentId INT NOT NULL,\n    StartDate DATETIME NOT NULL,\n    EndDate DATETIME NOT NULL,\n    UserId INT NOT NULL,\n    Status NVARCHAR(50) DEFAULT 'pending', -- pending, approved, in-progress, completed, cancelled\n    Notes NVARCHAR(MAX),\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    UpdatedAt DATETIME DEFAULT GETDATE(),\n    FOREIGN KEY (RequestId) REFERENCES TestRequests(Id),\n    FOREIGN KEY (EquipmentId) REFERENCES Equipment(Id),\n    FOREIGN KEY (UserId) REFERENCES Users(Id)\n);\nGO\n\n-- Approvals Table (Approval Workflow)\nCREATE TABLE Approvals (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    RequestId INT NOT NULL,\n    ApprovalOrder INT,\n    ApproverId INT,\n    Status NVARCHAR(50) DEFAULT 'pending', -- pending, approved, rejected\n    Comments NVARCHAR(MAX),\n    ApprovedAt DATETIME,\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    FOREIGN KEY (RequestId) REFERENCES TestRequests(Id),\n    FOREIGN KEY (ApproverId) REFERENCES Users(Id)\n);\nGO\n\n-- Tasks Table\nCREATE TABLE Tasks (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    BookingId INT NOT NULL,\n    Status NVARCHAR(50) DEFAULT 'pending', -- pending, in-progress, completed\n    AssignedToId INT,\n    CreatedDate DATETIME DEFAULT GETDATE(),\n    CompletedDate DATETIME,\n    Notes NVARCHAR(MAX),\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    UpdatedAt DATETIME DEFAULT GETDATE(),\n    FOREIGN KEY (BookingId) REFERENCES Bookings(Id),\n    FOREIGN KEY (AssignedToId) REFERENCES Users(Id)\n);\nGO\n\n-- Audit Log Table\nCREATE TABLE AuditLogs (\n    Id INT PRIMARY KEY IDENTITY(1,1),\n    UserId INT,\n    Action NVARCHAR(255),\n    TableName NVARCHAR(255),\n    RecordId INT,\n    OldValue NVARCHAR(MAX),\n    NewValue NVARCHAR(MAX),\n    CreatedAt DATETIME DEFAULT GETDATE(),\n    FOREIGN KEY (UserId) REFERENCES Users(Id)\n);\nGO\n\n-- Create Indexes\nCREATE INDEX idx_equipment_status ON Equipment(Status);\nCREATE INDEX idx_testrequests_status ON TestRequests(Status);\nCREATE INDEX idx_testrequests_equipment ON TestRequests(EquipmentId);\nCREATE INDEX idx_bookings_equipment ON Bookings(EquipmentId);\nCREATE INDEX idx_bookings_startdate ON Bookings(StartDate);\nCREATE INDEX idx_tasks_status ON Tasks(Status);\nGO\n\nPRINT 'Database created successfully!';\n